custom_css:
.minha-logo { 
    font-size: 30px; 
    font-weight: 900; 
    font-style: italic;
    color: #ffb7ce;
    text-shadow: 2px 2px 0px #ffffff;
    letter-spacing: -1px;
    animation: bounce 2s infinite ease-in-out;
}

.minha-logo span { 
    color: #b2e2f2;
    text-shadow: 2px 2px 0px #ffffff;
}

@keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-6px); }
}
